package fizeau

import (
	"context"
	"testing"

	"github.com/easel/fizeau/internal/harnesses"
)

type testServiceOption func(*service)

func newTestService(t testing.TB, opts ServiceOptions, options ...testServiceOption) *service {
	t.Helper()

	svc := &service{
		opts:             opts,
		registry:         harnesses.NewRegistry(),
		harnessInstances: defaultHarnessInstances(),
	}
	for _, option := range options {
		option(svc)
	}
	return svc
}

func canceledRefreshContext() context.Context {
	ctx, cancel := context.WithCancel(context.Background())
	cancel()
	return ctx
}

func TestNewTestServiceInitializesCommonRuntimeState(t *testing.T) {
	svc := newTestService(t, ServiceOptions{})
	if svc.registry == nil {
		t.Fatal("registry is nil")
	}
}

package fizeau_test

import (
	"encoding/json"
	"os"
	"path/filepath"
	"testing"
	"time"
)

// TestMain isolates the agent_test package from the developer's live
// $HOME/.config/fizeau/config.yaml. Without this, calls like
// agent.New(agent.ServiceOptions{}) auto-load the user's real config —
// which has caused verify-worktree gates at older base revisions to fail
// when the live config contains provider types that revision didn't yet
// know about (agent-27806ad5).
//
// Per-test t.Setenv("HOME", ...) calls still take precedence for tests
// that need to plant a specific config on disk.
func TestMain(m *testing.M) {
	os.Exit(runTests(m))
}

func runTests(m *testing.M) int {
	tmp, err := os.MkdirTemp("", "agent-test-home-")
	if err != nil {
		panic(err)
	}
	defer os.RemoveAll(tmp)

	os.Setenv("HOME", tmp)
	os.Setenv("XDG_CONFIG_HOME", filepath.Join(tmp, ".config"))
	os.Setenv("FIZEAU_CACHE_DIR", filepath.Join(tmp, "cache"))
	installFreshQuotaFixtures(tmp)

	return m.Run()
}

func installFreshQuotaFixtures(root string) {
	now := time.Now().UTC().Format(time.RFC3339Nano)
	window := map[string]any{
		"name":           "test",
		"limit_id":       "codex",
		"window_minutes": 300,
		"used_percent":   10,
		"state":          "ok",
	}
	geminiWindow := map[string]any{
		"name":           "Flash",
		"limit_id":       "gemini-flash",
		"window_minutes": 1440,
		"used_percent":   10,
		"state":          "ok",
	}
	claudePath := filepath.Join(root, "claude-quota.json")
	codexPath := filepath.Join(root, "codex-quota.json")
	geminiPath := filepath.Join(root, "gemini-quota.json")
	os.Setenv("FIZEAU_CLAUDE_QUOTA_CACHE", claudePath)
	os.Setenv("FIZEAU_CODEX_QUOTA_CACHE", codexPath)
	os.Setenv("FIZEAU_GEMINI_QUOTA_CACHE", geminiPath)
	writeTestJSON(claudePath, map[string]any{
		"captured_at":         now,
		"five_hour_remaining": 90,
		"five_hour_limit":     100,
		"weekly_remaining":    900,
		"weekly_limit":        1000,
		"windows":             []map[string]any{window},
		"source":              "test",
		"account":             map[string]any{"plan_type": "Claude Max"},
	})
	writeTestJSON(codexPath, map[string]any{
		"captured_at": now,
		"windows":     []map[string]any{window},
		"source":      "test",
		"account":     map[string]any{"plan_type": "ChatGPT Pro"},
	})
	writeTestJSON(geminiPath, map[string]any{
		"captured_at": now,
		"windows":     []map[string]any{geminiWindow},
		"source":      "test",
		"account":     map[string]any{"plan_type": "Gemini OAuth"},
	})
}

func writeTestJSON(path string, payload any) {
	data, err := json.MarshalIndent(payload, "", "  ")
	if err != nil {
		panic(err)
	}
	if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
		panic(err)
	}
	if err := os.WriteFile(path, append(data, '\n'), 0o600); err != nil {
		panic(err)
	}
}

package fizeau_test

import (
	"errors"
	"os/exec"
	"strings"
	"testing"
)

func TestGitignoreIgnoresDDxRunStateDir(t *testing.T) {
	repoRoot := gitRepoRoot(t)

	assertGitTracked(t, repoRoot, ".ddx/beads.jsonl")

	ignored, output := gitCheckIgnore(t, repoRoot, ".ddx/run-state/example.json")
	if !ignored {
		t.Fatal("expected .ddx/run-state/example.json to be gitignored")
	}
	if output != ".ddx/run-state/example.json" {
		t.Fatalf("git check-ignore output = %q, want %q", output, ".ddx/run-state/example.json")
	}

	ignored, output = gitCheckIgnore(t, repoRoot, ".ddx/beads.jsonl")
	if ignored {
		t.Fatalf("expected tracked DDx audit file to remain unignored, got output %q", output)
	}
}

func gitRepoRoot(t testing.TB) string {
	t.Helper()

	cmd := exec.Command("git", "rev-parse", "--show-toplevel")
	out, err := cmd.Output()
	if err != nil {
		t.Fatalf("git rev-parse --show-toplevel: %v", err)
	}

	return strings.TrimSpace(string(out))
}

func assertGitTracked(t testing.TB, repoRoot, path string) {
	t.Helper()

	cmd := exec.Command("git", "ls-files", "--error-unmatch", path)
	cmd.Dir = repoRoot
	if out, err := cmd.CombinedOutput(); err != nil {
		t.Fatalf("git ls-files --error-unmatch %s: %v\n%s", path, err, strings.TrimSpace(string(out)))
	}
}

func gitCheckIgnore(t testing.TB, repoRoot, path string) (bool, string) {
	t.Helper()

	cmd := exec.Command("git", "check-ignore", path)
	cmd.Dir = repoRoot
	out, err := cmd.CombinedOutput()
	trimmed := strings.TrimSpace(string(out))
	if err == nil {
		return true, trimmed
	}

	var exitErr *exec.ExitError
	if errors.As(err, &exitErr) && exitErr.ExitCode() == 1 {
		return false, trimmed
	}

	t.Fatalf("git check-ignore %s: %v\n%s", path, err, trimmed)
	return false, ""
}
